<!-- Modulo de Cotizaciones -->
<template>
    <div>
        <div class="container-fluid p-l-0 p-r-0">
            <div class="page-header">
                <div class="row">
                    <div class="col-sm-6">
                        <h6><span>Cotizaciones</span></h6>
                        <ol class="breadcrumb">
                            <li class="breadcrumb-item">
                                <a href="/dashboard">Dashboard</a>
                            </li>
                            <li class="breadcrumb-item active">
                                <span class="text-muted">Cotizaciones</span>
                            </li>
                        </ol>
                    </div>
                    <div
                        class="col-12 col-md-6 d-flex align-items-start justify-content-end"
                    >
                        <template v-if="cashId">
                            <a
                                :href="`/${resource}/create`"
                                class="btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto"
                            >
                                <i class="icofont-plus-circle"></i>
                                <span>Nuevo</span>
                            </a>
                        </template>
                        <template v-else>
                            <a
                                :href="`/report_closed_cash`"
                                class="btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto"
                            >
                                <i class="icofont-plus-circle"></i>
                                <span>Abrir caja</span>
                            </a>
                        </template>
                    </div>
                </div>
            </div>
        </div>
        <div class="container-fluid p-l-0 p-r-0">
            <div class="card mb-0">
                <div class="card-header bg-primary">
                    <h4 class="my-0 text-white">
                        <i class="fas fa-file-alt"></i>
                        Cotizaciones</h4>
                </div>

                <div class="data-table-visible-columns">
                    <a  :href="`/${resource}/create`"
                        class="btn btn-outline-white btn-icon btn-icon-start w-100 w-md-auto">
                        <i class="fas fa-file-alt fa-lg"></i>
                        <i class="fa fa-plus"></i>
                        <span>Nuevo</span>
                    </a>
                </div>
                <div class="card-body">
                    <data-table :resource="resource"
                    :sellers="sellers"
                    >
                        <tr slot="heading" class="bg-primary">
                            <th class="text-white">#</th>
                            <th class="text-white text-end">Acciones</th>
                            <th class="text-white text-center">Fecha Emisión</th>
                            <th class="text-white text-center" v-if="columns.delivery_date.visible">  Fecha Entrega</th>
                            <th class="text-white">Vendedor</th>
                            <th class="text-white">Cliente</th>
                            <th class="text-white">Estado</th>
                            <th class="text-white">Cotización</th>
                            <th class="text-white">Comprobantes</th>
                            <th class="text-white">Nota de venta</th>
                            <th class="text-white">Oportunidad Venta</th>
                            <th class="text-white" v-if="columns.contract.visible">Contrato</th>
                            <!-- <th>Estado</th> -->
                            <th class="text-white text-center">Moneda</th>
                            <th
                                class="text-end text-white"
                                v-if="columns.total_exportation.visible"
                            >
                                T.Exportación
                            </th>
                            <th
                                class="text-endtext-white"
                                v-if="columns.total_free.visible"
                            >
                                T.Gratuito
                            </th>
                            <th
                                class="text-end text-white"
                                v-if="columns.total_unaffected.visible"
                            >
                                T.Inafecta
                            </th>
                            <th
                                class="text-end text-white"
                                v-if="columns.total_exonerated.visible"
                            >
                                T.Exonerado
                            </th>
                            <th class="text-end text-white">T.Gravado</th>
                            <th class="text-end text-white">T.Igv</th>
                            <th class="text-end text-white">Total</th>
                            <th class="text-center text-white">PDF</th>
                        </tr>

                        <tr></tr>
                        <tr
                            slot-scope="{ index, row }"
                            :class="{
                                anulate_color: row.state_type_id == '11'
                            }"
                        >
                            <td>{{ index }}</td>

                            <td class="text-end">
                                <div class="d-flex flex-wrap">
                                    <button
                                        v-if="
                                            row.state_type_id != '11' &&
                                                row.btn_generate &&
                                                (typeUser == 'admin' ||
                                                    typeUser == 'superadmin') &&
                                                soapCompany != '03'
                                        "
                                        type="button"
                                        class="m-1 btn waves-effect waves-light btn-sm btn-info"
                                        @click.prevent="clickOptions(row.id)"
                                    >
                                        Generar comprobante
                                    </button>

                                    <a
                                        v-if="
                                            row.documents.length == 0 &&
                                                row.state_type_id != '11'
                                        "
                                        :href="`/${resource}/edit/${row.id}`"
                                        type="button"
                                        class="m-1 btn waves-effect waves-light  btn-sm btn-info"
                                        >Editar</a
                                    >
                                    <button
                                        v-if="
                                            row.documents.length == 0 &&
                                                row.state_type_id != '11'
                                        "
                                        type="button"
                                        class="m-1 btn waves-effect waves-light btn-sm btn-danger"
                                        @click.prevent="clickAnulate(row.id)"
                                    >
                                        Anular
                                    </button>
                                    <button
                                        @click="duplicate(row.id)"
                                        type="button"
                                        class="m-1 btn waves-effect waves-light btn-sm btn-info"
                                    >
                                        Duplicar
                                    </button>
                                    <a
                                        v-if="
                                            row.btn_generate_cnt &&
                                                row.state_type_id != '11'
                                        "
                                        :href="
                                            `/contracts/generate-quotation/${row.id}`
                                        "
                                        class="m-1 btn waves-effect waves-light btn-sm btn-primary m-1__2"
                                        >Generar contrato</a
                                    >
                                </div>
                            </td>
                            <td class="text-center">{{ row.date_of_issue }}</td>
                            <td
                                class="text-center"
                                v-if="columns.delivery_date.visible"
                            >
                                {{ row.delivery_date }}
                            </td>
                            <td>{{ row.user_name }}</td>
                            <td>
                                {{ row.customer_name }}<br /><small
                                    v-text="row.customer_number"
                                ></small>
                            </td>
                            <td>
                                <template v-if="row.state_type_id == '11'">
                                    {{ row.state_type_description }}
                                </template>
                                <template v-else>
                                    <el-select
                                        v-model="row.state_type_id"
                                        @change="changeStateType(row)"
                                        style="width:120px !important"
                                    >
                                        <el-option
                                            v-for="option in state_types"
                                            :key="option.id"
                                            :value="option.id"
                                            :label="option.description"
                                        ></el-option>
                                    </el-select>
                                </template>
                            </td>
                            <td>{{ row.identifier }}</td>
                            <td>
                                <template
                                    v-for="(document, i) in row.documents"
                                >
                                    <label
                                        ::key="i"
                                        v-text="document.number_full"
                                        class="d-block"
                                    ></label>
                                </template>
                            </td>
                            <td>
                                <template
                                    v-for="(sale_note, i) in row.sale_notes"
                                >
                                    <label
                                        ::key="i"
                                        v-text="sale_note.identifier"
                                        class="d-block"
                                    ></label>
                                </template>
                            </td>
                            <td>
                                <!-- {{ row.sale_opportunity_number_full }} -->

                                <el-popover
                                    placement="right"
                                    v-if="row.sale_opportunity"
                                    width="400"
                                    trigger="click"
                                >
                                    <div class="col-md-12 mt-4">
                                        <table>
                                            <tr>
                                                <td>
                                                    <strong>O. Venta: </strong>
                                                </td>
                                                <td>
                                                    <strong>{{
                                                        row.sale_opportunity_number_full
                                                    }}</strong>
                                                </td>
                                            </tr>
                                            <tr class="mt-4 mb-4">
                                                <td>
                                                    <strong>F. Emisión:</strong>
                                                </td>
                                                <td>
                                                    <strong>{{
                                                        row.date_of_issue
                                                    }}</strong>
                                                </td>
                                            </tr>
                                        </table>

                                        <div class="table-responsive mt-4">
                                            <table class="table">
                                                <thead>
                                                    <tr>
                                                        <th>#</th>
                                                        <th>Descripción</th>
                                                        <th>Cantidad</th>
                                                        <th>Total</th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    <tr
                                                        v-for="(row,
                                                        index) in row
                                                            .sale_opportunity
                                                            .items"
                                                        :key="index"
                                                    >
                                                        <td>{{ index + 1 }}</td>
                                                        <td>
                                                            {{
                                                                row.item
                                                                    .description
                                                            }}
                                                        </td>
                                                        <td>
                                                            {{ row.quantity }}
                                                        </td>
                                                        <td>{{ row.total }}</td>
                                                    </tr>
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                    <el-button slot="reference">
                                        <i class="fa fa-eye"></i
                                    ></el-button>
                                </el-popover>
                            </td>
                            <!-- <td>{{ row.state_type_description }}</td> -->
                            <td v-if="columns.contract.visible">
                                {{ row.contract_number_full }}
                            </td>
                            <td class="text-center">
                                {{ row.currency_type_id }}
                            </td>
                            <td
                                class="text-end"
                                v-if="columns.total_exportation.visible"
                            >
                                {{ row.total_exportation }}
                            </td>
                            <td
                                class="text-end"
                                v-if="columns.total_free.visible"
                            >
                                {{ row.total_free }}
                            </td>
                            <td
                                class="text-end"
                                v-if="columns.total_unaffected.visible"
                            >
                                {{ row.total_unaffected }}
                            </td>
                            <td
                                class="text-end"
                                v-if="columns.total_exonerated.visible"
                            >
                                {{ row.total_exonerated }}
                            </td>
                            <td class="text-end">{{ row.total_taxed }}</td>
                            <td class="text-end">{{ row.total_igv }}</td>
                            <td class="text-end">{{ row.total }}</td>
                            <td class="text-end">
                                <button
                                    type="button"
                                    class="btn waves-effect waves-light btn-xs btn-info"
                                    @click.prevent="clickOptionsPdf(row.id)"
                                >
                                    PDF
                                </button>
                            </td>
                        </tr>
                    </data-table>
                </div>

                <quotation-options
                    :showDialog.sync="showDialogOptions"
                    :recordId="recordId"
                    :showGenerate="true"
                    :showClose="true"
                ></quotation-options>

                <quotation-options-pdf
                    :showDialog.sync="showDialogOptionsPdf"
                    :recordId="recordId"
                    :showClose="true"
                ></quotation-options-pdf>
            </div>
        </div>
    </div>
</template>
<style scoped>
.anulate_color {
    color: red;
}
</style>
<script>
import QuotationOptions from "./partials/options.vue";
import QuotationOptionsPdf from "./partials/options_pdf.vue";
import DataTable from "../../components/DataTable.vue";
import { deletable } from "../../mixins/deletable";

export default {
    props: ["typeUser", "soapCompany"],
    mixins: [deletable],
    components: { DataTable, QuotationOptions, QuotationOptionsPdf },
    data() {
        return {
            resource: "quotations",
            recordId: null,
            showDialogOptions: false,
            showDialogOptionsPdf: false,
            state_types: [],
            cashId: null,
            sellers: [],
            columns: {
                total_exportation: {
                    title: "T.Exportación",
                    visible: false
                },
                total_unaffected: {
                    title: "T.Inafecto",
                    visible: false
                },
                total_exonerated: {
                    title: "T.Exonerado",
                    visible: false
                },
                total_free: {
                    title: "T.Gratuito",
                    visible: false
                },
                contract: {
                    title: "Contrato",
                    visible: false
                },
                delivery_date: {
                    title: "F.Entrega",
                    visible: false
                }
            }
        };
    },
    async created() {
        await this.filter();
        if(this.$cashId){
            this.cashId = this.$cashId;
        }
    },
    methods: {
        async changeStateType(row) {
            await this.updateStateType(
                `/${this.resource}/state-type/${row.state_type_id}/${row.id}`
            ).then(() => this.$eventHub.$emit("reloadData"));
        },
        filter() {
            this.$http.get(`/${this.resource}/filter`).then(response => {
                this.state_types = response.data.state_types;
                this.sellers = response.data.sellers;
            });
        },
        clickEdit(id) {
            this.recordId = id;
            this.showDialogFormEdit = true;
        },
        clickOptions(recordId = null) {
            this.recordId = recordId;
            this.showDialogOptions = true;
        },
        clickOptionsPdf(recordId = null) {
            this.recordId = recordId;
            this.showDialogOptionsPdf = true;
        },
        clickAnulate(id) {
            this.anular(`/${this.resource}/anular/${id}`).then(() =>
                this.$eventHub.$emit("reloadData")
            );
        },
        duplicate(id) {
            this.$http
                .post(`${this.resource}/duplicate`, { id })
                .then(response => {
                    if (response.data.success) {
                        this.$message.success(
                            "Se guardaron los cambios correctamente."
                        );
                        this.$eventHub.$emit("reloadData");
                    } else {
                        this.$message.error("No se guardaron los cambios");
                    }
                })
                .catch(error => {});
            this.$eventHub.$emit("reloadData");
        }
    }
};
</script>



